import "./form.css";

import { Form } from "radix-ui";
import { cn } from "tailwind-variants";

import { FormContext } from "./form.context";
import { formVariants } from "./form.variants";

export type FormRootProps = React.ComponentProps<typeof Form.Root>;

export const FormRoot = ({ className, ...props }: FormRootProps) => {
  const slots = formVariants();

  return (
    <FormContext value={{ slots }}>
      <Form.Root className={cn(slots.root(), className)} {...props} />
    </FormContext>
  );
};

import { Form } from "radix-ui";
import { cn } from "tailwind-variants";

import { useFormContext } from "./form.context";

export type FormFieldProps = React.ComponentProps<typeof Form.Field>;

export const FormField = ({ className, ...props }: FormFieldProps) => {
  const { slots } = useFormContext();

  return <Form.Field className={cn(slots.field(), className)} {...props} />;
};

import { Form } from "radix-ui";
import { cn } from "tailwind-variants";

import { useFormContext } from "./form.context";

export type FormLabelProps = React.ComponentProps<typeof Form.Label>;

export const FormLabel = ({ className, ...props }: FormLabelProps) => {
  const { slots } = useFormContext();

  return <Form.Label className={cn(slots.label(), className)} {...props} />;
};

import { Form } from "radix-ui";

export type FormControlProps = React.ComponentProps<typeof Form.Control>;

export const FormControl = (props: FormControlProps) => {
  return <Form.Control asChild {...props} />;
};

import { Form } from "radix-ui";
import { cn } from "tailwind-variants";

import { useFormContext } from "./form.context";

export type FormMessageProps = React.ComponentProps<typeof Form.Message>;

export const FormMessage = ({ className, ...props }: FormMessageProps) => {
  const { slots } = useFormContext();

  return <Form.Message className={cn(slots.message(), className)} {...props} />;
};

import { Form } from "radix-ui";

export type FormSubmitProps = React.ComponentProps<typeof Form.Submit>;

export const FormSubmit = (props: FormSubmitProps) => {
  return <Form.Submit asChild {...props} />;
};

import { createContext, useContext } from "react";

import { formVariants } from "./form.variants";

export type FormContext = {
  slots: ReturnType<typeof formVariants>;
};

export const FormContext = createContext<FormContext | null>(null);

export const useFormContext = () => {
  const context = useContext(FormContext);
  if (!context) {
    throw new Error("useFormContext must be used within a Form");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const formVariants = tv({
  slots: {
    control: "form__control",
    field: "form__field",
    label: "form__label",
    message: "form__message",
    root: "form",
    submit: "form__submit",
  },
});

export type FormVariants = VariantProps<typeof formVariants>;

.form {
  @apply w-full space-y-4;
}

.form__field {
  @apply grid gap-2;
}

.form__label {
  @apply text-sm leading-none font-medium;

  &[data-invalid] {
    @apply text-destructive;
  }
}

.form__control {
  @apply w-full;
}

.form__message {
  @apply text-destructive text-xs;
}

.form__submit {
  @apply w-full;
}

import { FormControl } from "./form-control";
import { FormField } from "./form-field";
import { FormLabel } from "./form-label";
import { FormMessage } from "./form-message";
import { FormRoot } from "./form-root";
import { FormSubmit } from "./form-submit";

export const Form = {
  Control: FormControl,
  Field: FormField,
  Label: FormLabel,
  Message: FormMessage,
  Root: FormRoot,
  Submit: FormSubmit,
};

export { FormControl, FormField, FormLabel, FormMessage, FormRoot, FormSubmit };

export type { FormControlProps } from "./form-control";

export type { FormFieldProps } from "./form-field";

export type { FormLabelProps } from "./form-label";
export type { FormMessageProps } from "./form-message";
export type { FormRootProps } from "./form-root";
export type { FormSubmitProps } from "./form-submit";
export { FormContext, useFormContext } from "./form.context";
export { type FormVariants, formVariants } from "./form.variants";
